#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long n;
        if (scanf("%lld", &n) != 1) return 0;
        long long k = n / 2;               // number of even numbers
        long long ans = k * (k + 1);        // sum of evens
        printf("%lld\n", ans);
    }
    return 0;
}

